package com.example.backgammon;
import java.util.Set;
import android.content.Context;
import android.graphics.Canvas;
import android.graphics.Color;
import android.graphics.Paint;
import android.util.AttributeSet;
import android.view.MotionEvent;
import android.view.View;

public class BackgammonBoardView extends View {

    private final Paint paint = new Paint(Paint.ANTI_ALIAS_FLAG);
    private final GamePlay gamePlay = new GamePlay();

    private float triangleWidth;
    private float barWidth;
    private float pieceRadius;

    private float topBaseY;
    private float bottomBaseY;
    private int highlightedPiece = -1; // הנקודה של השחקן שנלחץ
    private float horizontalOffset = 56f;
    private float rightBoardOffset = 30f;
    private float verticalSpacingFactor = 1.7f;
    private float targetCircleFactor = 1.17f;

    public BackgammonBoardView(Context context, AttributeSet attrs) {
        super(context, attrs);
    }

    @Override
    protected void onSizeChanged(int w, int h, int oldw, int oldh) {
        super.onSizeChanged(w, h, oldw, oldh);
        barWidth = w * 0.015f;
        triangleWidth = (w - barWidth) / 12f * 0.867f;
        pieceRadius = triangleWidth * 0.45f;

        topBaseY = pieceRadius * 5f;
        bottomBaseY = h - pieceRadius * 5f;

        updateAllPiecePositions();
    }

    private void drawLegalTargets(Canvas c) {
        Piece selectedPiece = gamePlay.getSelectedPiece();
        if (selectedPiece == null) return;

        Set<Integer> targets = gamePlay.getLegalTargets();
        Piece[][] board = gamePlay.getBoard();

        for (int point : targets) {
            float[] pos = calculateBasePosition(point);
            int stackHeight = getOccupiedCount(point);
            boolean isTop = point > 12;
            float y = isTop
                    ? topBaseY + stackHeight * pieceRadius * verticalSpacingFactor
                    : bottomBaseY - stackHeight * pieceRadius * verticalSpacingFactor;

            // מחשבים חסימה
            int enemyCount = gamePlay.getEnemyCount(point);
            boolean blocked = enemyCount >= 2;

            paint.setColor(blocked ? Color.RED : Color.GREEN);
            paint.setStyle(Paint.Style.FILL);
            c.drawCircle(pos[0], y, pieceRadius * targetCircleFactor, paint);
        }
    }
    @Override
    protected void onDraw(Canvas c) {
        super.onDraw(c);

        drawLegalTargets(c);

        Piece[][] board = gamePlay.getBoard();
        for (Piece[] col : board) {
            for (Piece p : col) {
                if (p != null) drawPiece(c, p);
            }
        }

        drawBarPieces(c);
        drawBearOffButtons(c);
        drawDiceButton(c);
        drawDice(c);
    }

    private int getOccupiedCount(int point) {
        int count = 0;
        for (Piece p : gamePlay.getBoard()[point - 1])
            if (p != null) count++;
        return count;
    }

    private void drawBearOffButtons(Canvas c) {
        paint.setStyle(Paint.Style.FILL);
        float centerY = getHeight() / 2f;
        float buttonHalfWidth = 20f;
        float buttonHalfHeight = 50f;

        // לבן
        float whiteRightX = horizontalOffset + 1f;
        float whiteX = whiteRightX - buttonHalfWidth;
        float whiteY = centerY;
        paint.setColor(Color.LTGRAY);
        c.drawRect(whiteX - buttonHalfWidth, whiteY - buttonHalfHeight,
                whiteX + buttonHalfWidth, whiteY + buttonHalfHeight, paint);

        // שחור
        float blackLeftX = getWidth() - horizontalOffset - 1f;
        float blackX = blackLeftX + buttonHalfWidth;
        float blackY = centerY;
        paint.setColor(Color.DKGRAY);
        c.drawRect(blackX - buttonHalfWidth, blackY - buttonHalfHeight,
                blackX + buttonHalfWidth, blackY + buttonHalfHeight, paint);
    }

    private void drawBarPieces(Canvas c) {
        Piece[][] bar = gamePlay.getBar();
        float centerX = getWidth() / 2f;
        float centerY = getHeight() / 2f;
        float spacing = pieceRadius * 1.4f;

        drawBarStack(c, bar[0], centerX, centerY + spacing, 1);
        drawBarStack(c, bar[1], centerX, centerY - spacing, -1);
    }

    private void drawBarStack(Canvas c, Piece[] stack, float x, float baseY, int dir) {
        int slot = 0;
        for (Piece p : stack) {
            if (p == null) continue;
            float y = baseY + dir * slot * pieceRadius * 1.4f;
            p.setPosition(x, y);
            drawPiece(c, p);
            slot++;
        }
    }

    private void drawDiceButton(Canvas c) {
        paint.setStyle(Paint.Style.FILL);
        float btnWidth = 150f;
        float btnHeight = 60f;
        float x = getWidth() / 2f - btnWidth / 2f;
        float y = getHeight() - btnHeight - 30f;

        paint.setColor(Color.BLUE);
        c.drawRect(x, y, x + btnWidth, y + btnHeight, paint);

        paint.setColor(Color.WHITE);
        paint.setTextSize(36f);
        paint.setTextAlign(Paint.Align.CENTER);
        c.drawText("Roll Dice", x + btnWidth / 2f, y + btnHeight / 2f + 12f, paint);
    }

    private void drawDice(Canvas c) {
        if (!gamePlay.isDiceRolled()) return;

        int d1 = gamePlay.getDice().getDie1();
        int d2 = gamePlay.getDice().getDie2();

        paint.setStyle(Paint.Style.FILL);
        float size = 50f;
        float y = getHeight() - 120f;
        float x = getWidth() / 2f - size - 10f;

        paint.setColor(Color.WHITE);
        c.drawRect(x, y, x + size, y + size, paint);
        paint.setColor(Color.BLACK);
        paint.setTextSize(36f);
        paint.setTextAlign(Paint.Align.CENTER);
        c.drawText(String.valueOf(d1), x + size / 2f, y + size / 2f + 12f, paint);

        x += size + 20f;
        paint.setColor(Color.WHITE);
        c.drawRect(x, y, x + size, y + size, paint);
        paint.setColor(Color.BLACK);
        c.drawText(String.valueOf(d2), x + size / 2f, y + size / 2f + 12f, paint);
    }

    @Override
    public boolean onTouchEvent(MotionEvent e) {
        if (e.getAction() != MotionEvent.ACTION_DOWN) return true;

        float x = e.getX();
        float y = e.getY();

        float btnWidth = 150f, btnHeight = 60f;
        float btnX = getWidth() / 2f - btnWidth / 2f;
        float btnY = getHeight() - btnHeight - 30f;

        if (x >= btnX && x <= btnX + btnWidth && y >= btnY && y <= btnY + btnHeight) {
            gamePlay.rollDice();
            highlightedPiece = -1;
            updateAllPiecePositions();
            invalidate();
            return true;
        }

        float centerY = getHeight() / 2f;
        float buttonHalfWidth = 20f, buttonHalfHeight = 50f;

        float whiteX = horizontalOffset + 1f - buttonHalfWidth;
        float whiteY = centerY;

        if (x >= whiteX && x <= whiteX + 2 * buttonHalfWidth &&
                y >= whiteY - buttonHalfHeight && y <= whiteY + buttonHalfHeight) {
            gamePlay.bearOffSelected(false);
            highlightedPiece = -1;
        }

        float blackX = getWidth() - horizontalOffset - 1f - buttonHalfWidth;
        float blackY = centerY;

        if (x >= blackX && x <= blackX + 2 * buttonHalfWidth &&
                y >= blackY - buttonHalfHeight && y <= blackY + buttonHalfHeight) {
            gamePlay.bearOffSelected(true);
            highlightedPiece = -1;
        }

        // BAR קודם!
        if (isTouchOnWhiteBar(x, y)) {
            gamePlay.selectFromBar(true);
            highlightedPiece = -1;
            updateAllPiecePositions();
            invalidate();
            return true;
        } else if (isTouchOnBlackBar(x, y)) {
            gamePlay.selectFromBar(false);
            highlightedPiece = -1;
            updateAllPiecePositions();
            invalidate();
            return true;
        } else {
            // בדיקה אם יש אבנים ב-BAR
            if (gamePlay.hasPiecesInBar(gamePlay.isWhiteTurn())) {
                updateAllPiecePositions();
                invalidate();
                return true;
            }

            int pointClicked = findPieceByTouch(x, y);

            if (pointClicked != -1) {
                highlightedPiece = pointClicked;
                gamePlay.selectPiece(pointClicked);
            } else {
                int target = findTargetByTouch(x, y);
                if (target != -1) {
                    gamePlay.movePiece(target);
                    highlightedPiece = -1;
                } else {
                    highlightedPiece = -1;
                }
            }
        }

        updateAllPiecePositions();
        invalidate();
        return true;
    }

    private int findPieceByTouch(float x, float y) {
        Piece[][] board = gamePlay.getBoard();
        for (int t = 0; t < 24; t++) {
            for (Piece p : board[t]) {
                if (p == null) continue;
                float dx = x - p.getX();
                float dy = y - p.getY();
                if (dx * dx + dy * dy <= pieceRadius * pieceRadius * 2) return t + 1;
            }
        }
        return -1;
    }

    private int findTargetByTouch(float x, float y) {
        for (int p : gamePlay.getLegalTargets()) {
            float[] pos = calculateBasePosition(p);
            int stackHeight = getOccupiedCount(p);
            boolean isTop = p > 12;
            float yPos = isTop ? topBaseY + stackHeight * pieceRadius * verticalSpacingFactor : bottomBaseY - stackHeight * pieceRadius * verticalSpacingFactor;

            float dx = x - pos[0];
            float dy = y - yPos;

            if (dx * dx + dy * dy <= pieceRadius * pieceRadius) {
                return p;
            }
        }
        return -1;
    }

    private void drawPiece(Canvas c, Piece p) {
        paint.setStyle(Paint.Style.FILL);
        boolean isSelected = p == gamePlay.getSelectedPiece();
        if (isSelected) {
            if (p.isWhite()) paint.setColor(Color.rgb(144, 238, 144));
            else paint.setColor(Color.rgb(0, 100, 0));
        } else if (highlightedPiece != -1 && p == gamePlay.getTopPieceAtPoint(highlightedPiece)) {
            if (p.isWhite()) paint.setColor(Color.rgb(144, 238, 144));
            else paint.setColor(Color.rgb(0, 100, 0));
        } else {
            paint.setColor(p.isWhite() ? Color.WHITE : Color.BLACK);
        }

        c.drawCircle(p.getX(), p.getY(), pieceRadius, paint);
        paint.setStyle(Paint.Style.STROKE);
        paint.setColor(Color.BLACK);
        paint.setStrokeWidth(3);
        c.drawCircle(p.getX(), p.getY(), pieceRadius, paint);
        paint.setStyle(Paint.Style.FILL);
    }

    private void updateAllPiecePositions() {
        Piece[][] board = gamePlay.getBoard();
        for (int t = 0; t < 24; t++) {
            int slot = 0;
            for (int s = 0; s < 10; s++) {
                if (board[t][s] == null) continue;
                float[] pos = calculatePiecePosition(t + 1, slot);
                board[t][s].setPosition(pos[0], pos[1]);
                slot++;
            }
        }

        Piece[][] bar = gamePlay.getBar();
        float centerX = getWidth() / 2f;
        float centerY = getHeight() / 2f;
        float spacing = pieceRadius * 1.4f;

        int slot_white = 0;
        for (Piece p : bar[0]) {
            if (p == null) continue;
            float y = centerY + spacing + slot_white * pieceRadius * 1.4f;
            p.setPosition(centerX, y);
            slot_white++;
        }

        int slot_black = 0;
        for (Piece p : bar[1]) {
            if (p == null) continue;
            float y = centerY - spacing - slot_black * pieceRadius * 1.4f;
            p.setPosition(centerX, y);
            slot_black++;
        }
    }

    private boolean isTouchOnWhiteBar(float x, float y) {
        float centerX = getWidth() / 2f;
        float centerY = getHeight() / 2f;
        float spacing = pieceRadius * 1.4f;
        float barY = centerY + spacing;
        float dx = x - centerX;
        float dy = y - barY;

        int whiteBarCount = 0;
        for (Piece p : gamePlay.getBar()[0]) {
            if (p != null) whiteBarCount++;
        }
        float maxDy = whiteBarCount * pieceRadius * 1.4f;

        return Math.abs(dx) <= pieceRadius && Math.abs(dy) <= pieceRadius + maxDy;
    }

    private boolean isTouchOnBlackBar(float x, float y) {
        float centerX = getWidth() / 2f;
        float centerY = getHeight() / 2f;
        float spacing = pieceRadius * 1.4f;
        float barY = centerY - spacing;
        float dx = x - centerX;
        float dy = y - barY;

        int blackBarCount = 0;
        for (Piece p : gamePlay.getBar()[1]) {
            if (p != null) blackBarCount++;
        }
        float maxDy = blackBarCount * pieceRadius * 1.4f;

        return Math.abs(dx) <= pieceRadius && Math.abs(dy) <= pieceRadius + maxDy;
    }

    private float[] calculatePiecePosition(int point, int slot) {
        float centerX = calculateCenterX(point);
        boolean isTop = point > 12;
        Piece[][] board = gamePlay.getBoard();
        int count = 0;
        for (Piece p : board[point - 1]) if (p != null) count++;
        float spacing = pieceRadius * verticalSpacingFactor;
        if (count > 5) spacing = pieceRadius * 1.2f;
        float y = isTop ? topBaseY + slot * spacing : bottomBaseY - slot * spacing;
        return new float[]{centerX, y};
    }

    private float[] calculateBasePosition(int point) {
        float x = calculateCenterX(point);
        float y = point > 12 ? topBaseY : bottomBaseY;
        return new float[]{x, y};
    }

    private float calculateCenterX(int point) {
        int safePoint = Math.max(1, Math.min(24, point));
        int index = safePoint > 12 ? safePoint - 13 : 12 - safePoint;
        float x = index * triangleWidth + triangleWidth / 2f + horizontalOffset;
        if (index >= 6) x += barWidth + rightBoardOffset;
        return x;
    }
}

