        for (Piece p : bar[0]) {
            if (p == null) continue;
            float y = centerY + spacing + slot_white * pieceRadius * 1.4f;
            p.setPosition(centerX, y);
            slot_white++;
        }

        int slot_black = 0;
        for (Piece p : bar[1]) {
            if (p == null) continue;
            float y = centerY - spacing - slot_black * pieceRadius * 1.4f;
            p.setPosition(centerX, y);
            slot_black++;
        }
    }

    private boolean isTouchOnWhiteBar(float x, float y) {
        if (pieceRadius == 0) return false;
        float centerX = getWidth() / 2f;
        float centerY = getHeight() / 2f;
        float spacing = pieceRadius * 1.4f;
        float barY = centerY + spacing;
        float dx = x - centerX;
        float dy = y - barY;

        return Math.abs(dx) <= pieceRadius * 1.5f && Math.abs(dy) <= pieceRadius * 2f;
    }

    private boolean isTouchOnBlackBar(float x, float y) {
        if (pieceRadius == 0) return false;
        float centerX = getWidth() / 2f;
        float centerY = getHeight() / 2f;
        float spacing = pieceRadius * 1.4f;
        float barY = centerY - spacing;
        float dx = x - centerX;
        float dy = y - barY;

        return Math.abs(dx) <= pieceRadius * 1.5f && Math.abs(dy) <= pieceRadius * 2f;
    }

    private float[] calculatePiecePosition(int point, int slot) {
        float centerX = calculateCenterX(point);
        boolean isTop = point > 12;
        Piece[][] board = gamePlay.getBoard();
        int count = 0;
        for (Piece p : board[point - 1]) if (p != null) count++;
        float spacing = pieceRadius * verticalSpacingFactor;
        if (count > 5) spacing = pieceRadius * 1.2f;
        float y = isTop ? topBaseY + slot * spacing : bottomBaseY - slot * spacing;
        return new float[]{centerX, y};
    }

    private float[] calculateBasePosition(int point) {
        float x = calculateCenterX(point);
        float y = point > 12 ? topBaseY : bottomBaseY;
        return new float[]{x, y};
    }

    private float calculateCenterX(int point) {
        int safePoint = Math.max(1, Math.min(24, point));
        int index = safePoint > 12 ? safePoint - 13 : 12 - safePoint;
        float x = index * triangleWidth + triangleWidth / 2f + horizontalOffset;
        if (index >= 6) x += barWidth + rightBoardOffset;
        return x;
    }
}
